    private void parseDownloadInfo(String downloadInfoString) {
        // downloadInfo: rootDomainId, mappingKey, selectedField_1, selectedField_2..
        // if no mappingKey it'll be an empty String
        String[] downloadInfo = downloadInfoString.split("\\|");
        for (String selectedInfo : downloadInfo) {
            String[] selectedInfoArr = selectedInfo.split(",");
            int arrLength = selectedInfoArr.length;
            if(arrLength < 3) continue; // at least: rootDomainId, mappingKey, selectedField1

            int rootDomainId = Encoder.parseInt(selectedInfoArr[0], Const.NODOMAIN);
            if(rootDomainId == Const.NODOMAIN) continue;

            AttachmentDownloadInfo info;
            if(!downloadObj.containsKey(rootDomainId)) {
                info = new AttachmentDownloadInfo();
                downloadObj.put(rootDomainId, info);
            } else {
                info = downloadObj.get(rootDomainId);
            }

            info.isSubTable(rootDomainId != form.getRootDomainId());

            int mappingKey = Encoder.parseInt(selectedInfoArr[1], Const.NODOMAIN);
            info.setMappingKey(mappingKey);

//            System.out.println("===== "+rootDomainId+" =====");
            for(int _i = 2;_i < arrLength;_i++) {
                int selectedDomainId = Encoder.parseInt(selectedInfoArr[_i], Const.NODOMAIN);
                info.addSelectedFieldsId(selectedDomainId);
            }
//            System.out.println(info.getSelectedFieldsId());
        }
    }

    private boolean checkIfUserCanViewThisRecord(NUIForm form, User user, APIEntry record) {
        int userRightOnThisSheet = form.checkRight(user);
        if(Const.VIEWER <= userRightOnThisSheet) return true;
        if(Const.USER == userRightOnThisSheet) {
            String createUser = record.getFieldValue("_create_user");
            if(createUser != null && createUser.equals(user.getUserId())) return true;
        }
        return false;
    }

    private CellStyle getHeaderCellStyle(Workbook wb) {
        return getCellStyle(wb, true);
    }

    private CellStyle getDataCellStyle(Workbook wb) {
        return getCellStyle(wb, false);
    }

    private CellStyle getCellStyle(Workbook wb, boolean isHeader) {
        CellStyle cellStyle = wb.createCellStyle();
        cellStyle.setVerticalAlignment(VerticalAlignment.CENTER);
        Font font = wb.createFont();
        setDefaultFontName(font, bundle);
        if(isHeader) {
            font.setBold(true);
            cellStyle.setAlignment(HorizontalAlignment.RIGHT);
        }
        cellStyle.setFont(font);

        return cellStyle;
    }

    private void processMappingFileHeader(Workbook wb, AttachmentDownloadInfo downloadInfo) {
        Sheet sheet = wb.createSheet("MappingFile");
        sheet.setDisplayGridlines(false);
        sheet.setPrintGridlines(false);

        CellStyle headerCellStyle = getHeaderCellStyle(wb);

        Row headerRow = sheet.createRow(0);
        headerRow.setHeightInPoints(20);

        // Mapping Key
        Cell firstCell = headerRow.createCell(0);
        CellInfo mappingKeyFieldInfo = form.getField(downloadInfo.getMappingKey());
        firstCell.setCellStyle(headerCellStyle);
        firstCell.setCellValue(mappingKeyFieldInfo.getValue());

        // selected fields
        int cellIndex = 1;
        Set<Integer> selectedFieldsId = downloadInfo.getSelectedFieldsId();
        for(int fieldId : selectedFieldsId) {
            CellInfo targetKeyFieldInfo = form.getField(fieldId);
            Cell _cell = headerRow.createCell(cellIndex);
            _cell.setCellStyle(headerCellStyle);
            _cell.setCellValue(targetKeyFieldInfo.getValue());
            cellIndex++;
        }
    }

    private List<String> zipFiles(ZipOutputStream zout, List<String> fieldValues) throws Exception {
        List<String> fileNames = new ArrayList<>();
        for(String fileName : fieldValues) {
            if(fileName.isEmpty()) continue;
            File file = FileHelper.getLocalFileFromFullFileLink(apName, fileName);
            if(!file.exists()) continue;
            fileName = fileRenamePolicy.rename(file).getName();
            fileName = fileName.replaceAll(invalidFileNamePattern, "_");
            fileNames.add(fileName);
            ZipEntry zipEntry = new ZipEntry(fileName);
            zout.putNextEntry(zipEntry);
            try(BufferedInputStream bis = new BufferedInputStream(new FileInputStream(file))) {
                byte[] buf = new byte[8192];
                int n;
                while((n = bis.read(buf)) > 0) {
                    zout.write(buf, 0, n);
                }
            } catch (Exception e) {
                e.printStackTrace();
            }
            zout.closeEntry();
        }

        return fileNames;
    }

    private void processRow(APIEntry entry, int entryIndex , int subTableKey, ZipOutputStream zout, AttachmentDownloadInfo downloadInfo, Sheet sheet, CellStyle dataCellStyle) throws Exception {
        Row dataRow = null;
        boolean isSubTable = subTableKey != Const.NODOMAIN;
        Set<Integer> selectedFields = downloadInfo.getSelectedFieldsId();
        if(sheet != null) {
            String mappingKeyValue;
            if(isSubTable)
                mappingKeyValue = entry.getSubtableFieldValue(subTableKey, entryIndex, String.valueOf(downloadInfo.getMappingKey()));
            else
                mappingKeyValue = entry.getFieldValue(downloadInfo.getMappingKey());

            dataRow = sheet.createRow(downloadInfo.getCurrentRow());
            dataRow.setHeightInPoints(20);
            Cell firstCell = dataRow.createCell(0);
            firstCell.setCellStyle(dataCellStyle);
            firstCell.setCellValue(mappingKeyValue);
        }

        int cellIndex = 1;
        for(int fieldId : selectedFields) {
            List<String> fieldValues;
            List<String> fileNames;
            if(isSubTable) {
                fieldValues = entry.getSubtableFieldValues(subTableKey, entryIndex, String.valueOf(fieldId));
                fileNames = zipFiles(zout, fieldValues);
            } else {
                fieldValues = entry.getFieldValues(fieldId);
                fileNames = zipFiles(zout, fieldValues);
            }

            if(dataRow != null) {
                Cell _cell = dataRow.createCell(cellIndex);
                _cell.setCellStyle(dataCellStyle);
                _cell.setCellValue(Joiner.on(",").join(fileNames));
                cellIndex++;
            }
        }

        downloadInfo.nextRow();
    }

    private void setDefaultFontName(Font font,RagicBundle bundle){
        if("zh-TW".equals(bundle.getString("langv5"))){
            font.setFontName("新細明體");
        }
        else if("zh-CN".equals(bundle.getString("langv5"))){
            font.setFontName("宋体");
        }
        else{
            font.setFontName("Century");
        }
    }

