  public void _jspService(final javax.servlet.http.HttpServletRequest request, final javax.servlet.http.HttpServletResponse response)
      throws java.io.IOException, javax.servlet.ServletException {

    final java.lang.String _jspx_method = request.getMethod();
    if (!"GET".equals(_jspx_method) && !"POST".equals(_jspx_method) && !"HEAD".equals(_jspx_method) && !javax.servlet.DispatcherType.ERROR.equals(request.getDispatcherType())) {
      response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED, "JSPs only permit GET POST or HEAD");
      return;
    }

    final javax.servlet.jsp.PageContext pageContext;
    javax.servlet.http.HttpSession session = null;
    final javax.servlet.ServletContext application;
    final javax.servlet.ServletConfig config;
    javax.servlet.jsp.JspWriter out = null;
    final java.lang.Object page = this;
    javax.servlet.jsp.JspWriter _jspx_out = null;
    javax.servlet.jsp.PageContext _jspx_page_context = null;


    try {
      response.setContentType("text/html; charset=UTF-8");
      pageContext = _jspxFactory.getPageContext(this, request, response,
      			null, true, 8192, true);
      _jspx_page_context = pageContext;
      application = pageContext.getServletContext();
      config = pageContext.getServletConfig();
      session = pageContext.getSession();
      out = pageContext.getOut();
      _jspx_out = out;


    apName = request.getParameter("a");
    String path = request.getParameter("p");
    int sheetIndex = Encoder.parseInt(request.getParameter("si"), -1);
    if(apName == null || path == null || sheetIndex == -1) return;
    form = AppManager.getFormPage(apName, path, sheetIndex);
    if(form == null) return;

    if(request.getParameter("di") == null) return;
    String downloadInfoString = Encoder.decodeURIComponent(request.getParameter("di"));
    downloadObj = new HashMap<>();
    parseDownloadInfo(downloadInfoString); // 解析 downloadInfoString 並存到 downloadObj

    bundle = (RagicBundle) session.getAttribute("RAGIC_BUNDLE");
    User user = (User) session.getAttribute("USER");

    int downloadSize = Encoder.parseInt(request.getParameter("size"), 1000);

    // create mapping File Header
    int mappingFileLimit = 1; // 目前只允許一個 mapping 檔
    int mappingFileCount = 0;
    for(Map.Entry<Integer,AttachmentDownloadInfo> downloadObjEntry : downloadObj.entrySet()) {
        int rootDomainId = downloadObjEntry.getKey();
        AttachmentDownloadInfo downloadInfo = downloadObjEntry.getValue();
        int mappingKey = downloadInfo.getMappingKey();
        boolean createMappingFile = mappingKey != Const.NODOMAIN;

        Workbook wb;
        if(createMappingFile) {
//            System.out.println("create "+rootDomainId+" workbook!");
            wb = new SXSSFWorkbook(500);
            processMappingFileHeader(wb, downloadInfo);
            downloadInfo.setWorkbook(wb);
            downloadInfo.nextRow();
            mappingFileCount++;
        }

        if(mappingFileCount >= mappingFileLimit) {
            break;
        }
    }

    String zipName = form.getRealname() + ".zip";
    zipName = zipName.replaceAll(invalidFileNamePattern, "");

    response.setHeader("Cache-Control", "no-cache"); //HTTP 1.1
    response.setHeader("Pragma", "no-cache"); //HTTP 1.0
    response.setDateHeader("Expires", 0);
    response.setHeader("Cache-Control", "max-age=60");
    response.setHeader("Cache-Control", "must-revalidate");
    response.setContentType("application/zip");
    response.setHeader("Content-Disposition", FileServlet.getContentDisposition("attachment", zipName, request));

    Log apLog = Log.createStandardLog().setFilePath(Log.MaintenanceLog.RAGIC_MASS_DOWNLOAD.getFilePath(apName));
    apLog.info(request.getRemoteAddr() + " " + (user != null? user.getUserId(): "guest user") + " download " + form.getUrl() + " "  + zipName + "(bulkDownload)");

    // Start to compress file
    APIQuery aq = new APIQuery(apName, path, sheetIndex);
    //aq.setLimitSize(downloadSize);
    aq.setIfEidNaming(true);
    // set filter
    NUIFormSet set;
    set = NUIFormSetInfo.loadBrowsingFormSet(session, apName, path, aq.getForm().getFormName());
    if (set != null && set.getFilters() != null) {
        Map<Integer, NUIFilter> filtersMap = new LinkedHashMap<>();
        for (NUIFilter f : set.getFilters()) {
            if (f.getOperand() == NUIFilter.OPERAND_SORT_ASC || f.getOperand() == NUIFilter.OPERAND_SORT_DESC)
                continue; // temporary solution for issue#04526
            filtersMap.put(f.getDomainId(), f);
        }
        aq.setFilters(filtersMap);
    }
    aq.setMaxRetrieveFieldSize(1024);
    aq.setIfIncludeInfo(true);//issue#15628

    APIResultsFull result = aq.getAPIResultsFull();
    try(ZipOutputStream zout = new ZipOutputStream(new CheckedOutputStream(response.getOutputStream(), new Adler32()), Charset.forName("UTF-8"))) {
        int count = 0;
        fileRenamePolicy = new RagicFileNonrepetitiveRenamePolicy();
        for(APIEntry entry:result){
            boolean userCanViewThisRecord = checkIfUserCanViewThisRecord(form, user, entry);//issue#15628
            if(!userCanViewThisRecord) continue;
            count++;
            if(count > downloadSize) break;
            for(Map.Entry<Integer,AttachmentDownloadInfo> _obj : downloadObj.entrySet()) {
                AttachmentDownloadInfo downloadInfo = _obj.getValue();
                Workbook wb = downloadInfo.getWorkbook();
                Sheet sheet = null;
                CellStyle dataCellStyle = null;
                if(wb != null) {
                    sheet = wb.getSheet("MappingFile");
                    dataCellStyle = getDataCellStyle(wb);
                }

                if(downloadInfo.isSubTable()) {
                    // SubTable
                    int subTableKey = _obj.getKey();
                    int subTableSize = entry.getSubtableSize(subTableKey);
                    for(int i = 0;i<subTableSize;i++) {
                        processRow(entry, i, subTableKey, zout, downloadInfo, sheet, dataCellStyle);
                    }
                } else {
                    // Independent Fields
                    processRow(entry, -1, Const.NODOMAIN, zout, downloadInfo, sheet, dataCellStyle);
                }
            }
        }

        // Add mapping file into zip
        for(Map.Entry<Integer,AttachmentDownloadInfo> _obj : downloadObj.entrySet()) {
            int rootDomainId = _obj.getKey();
            AttachmentDownloadInfo downloadInfo = _obj.getValue();
            Workbook wb = downloadInfo.getWorkbook();
            if(wb == null) continue;

            String fileName = "mappingFile_" + rootDomainId + ".xlsx";
            ZipEntry entry = new ZipEntry(fileName);
            zout.putNextEntry(entry);
            wb.write(zout);
            zout.closeEntry();
        }
    } catch (Exception e) {
        e.printStackTrace();
    }

    return;

    } catch (java.lang.Throwable t) {
      if (!(t instanceof javax.servlet.jsp.SkipPageException)){
        out = _jspx_out;
        if (out != null && out.getBufferSize() != 0)
          try {
            if (response.isCommitted()) {
              out.flush();
            } else {
              out.clearBuffer();
            }
          } catch (java.io.IOException e) {}
        if (_jspx_page_context != null) _jspx_page_context.handlePageException(t);
        else throw new ServletException(t);
      }
    } finally {
      _jspxFactory.releasePageContext(_jspx_page_context);
    }
  }
